import { ChatFlow } from 'flowise';

const detectToolLoop = (chatflow: ChatFlow, executionData: any[]) => {
  const toolCalls = executionData.filter(node => node.type === 'tool');
  const toolPatterns = new Map<string, number>();

  toolCalls.forEach((call, index) => {
    const signature = `${call.toolName}_${JSON.stringify(call.input)}`;
    toolPatterns.set(signature, (toolPatterns.get(signature) || 0) + 1);

    if (toolPatterns.get(signature)! > 5) {
      throw new Error(`Tool loop detected: ${signature} called ${toolPatterns.get(signature)} times`);
    }
  });
};

// Usage in Flowise callback
chatflow.on('executionEnd', (data) => detectToolLoop(chatflow, data.trace));
