const validateStateProgress = (prevState: any, currentState: any) => {
  const stateKeys = ['messages', 'toolResults', 'context'];
  let progressDetected = false;

  stateKeys.forEach(key => {
    if (JSON.stringify(prevState[key]) !== JSON.stringify(currentState[key])) {
      progressDetected = true;
    }
  });

  if (!progressDetected) {
    console.warn('No state progress detected - potential loop');
    return false;
  }
  return true;
};

// Flowise agent handoff hook
chatflow.on('agentHandoff', ({ prevState, currentState }) => {
  if (!validateStateProgress(prevState, currentState)) {
    chatflow.interrupt();
  }
});
