const detectCyclePattern = (trace: any[]) => {
  const nodeSequences: string[] = [];
  for (let i = 0; i < trace.length - 10; i++) {
    const sequence = trace.slice(i, i + 10).map(n => n.nodeId).join('-');
    nodeSequences.push(sequence);
  }

  const sequenceCount = new Map();
  nodeSequences.forEach(seq => {
    sequenceCount.set(seq, (sequenceCount.get(seq) || 0) + 1);
  });

  for (const [seq, count] of sequenceCount) {
    if (count > 3) {
      return { cycle: seq, repeats: count };
    }
  }
  return null;
};
