const toolDeduplicationMiddleware = {
  seenCalls: new Set<string>(),

  async beforeToolCall(toolName: string, input: any, sessionId: string): Promise<boolean> {
    const callKey = `${sessionId}_${toolName}_${JSON.stringify(input)}`;
    if (this.seenCalls.has(callKey)) {
      console.log('Skipping duplicate tool call:', callKey);
      return false;
    }
    this.seenCalls.add(callKey);
    return true;
  },

  resetSession(sessionId: string) {
    // Clear on new conversation
    this.seenCalls.clear();
  }
};

// Register in Flowise chatflow
chatflow.addMiddleware(toolDeduplicationMiddleware);
