import { BasicNode } from 'flowise';

class LoopBreakerNode extends BasicNode {
  iterationLimit = 5;
  currentCount = 0;

  async execute(input: any) {
    this.currentCount++;

    if (this.currentCount > this.iterationLimit) {
      return {
        output: 'LOOP_DETECTED',
        breakFlow: true,
        reason: `Exceeded ${this.iterationLimit} iterations`
      };
    }

    return { ...input, iteration: this.currentCount };
  }
}

// Add to Flowise flow
chatflow.nodes.push(new LoopBreakerNode());
