const progressGatekeeper = async (state: any, proposedAction: any) => {
  const lastState = state.history?.[state.history.length - 1];
  const progressMetrics = {
    newTokens: state.current.tokens > (lastState?.tokens || 0),
    newTools: state.toolsUsed.size > (lastState?.toolsUsed?.size || 0),
    contextChanged: JSON.stringify(state.context) !== JSON.stringify(lastState?.context)
  };

  if (!Object.values(progressMetrics).some(Boolean)) {
    return {
      approved: false,
      reason: 'No progress detected',
      fallback: 'Summarize findings and conclude'
    };
  }

  return { approved: true };
};

chatflow.on('beforeToolExecute', ({ state, action }) => 
  progressGatekeeper(state, action)
);
