import { Vex } from '@vex_dev/sdk';
import { ChatFlow } from 'flowise';

const vex = new Vex({
  projectId: 'your-project-id',
  apiKey: process.env.VEX_API_KEY
});

const flowiseCallback = async (event: any) => {
  // Auto-detect tool loops in Flowise traces
  await vex.detect({
    framework: 'flowise',
    trace: event.trace,
    sessionId: event.sessionId,
    problem: 'tool_loop',
    metadata: {
      nodeTypes: event.nodes.map((n: any) => n.type),
      toolCalls: event.toolsCalled
    }
  });
};

// Install Vex callback in Flowise (drag-and-drop or config)
const chatflow = new ChatFlow();
chatflow.addCallback('executionComplete', flowiseCallback);
chatflow.addCallback('agentHandoff', flowiseCallback);
chatflow.addCallback('toolExecuted', flowiseCallback);

// Vex auto-remediates detected loops
vex.on('loop_detected', async (alert) => {
  await vex.remediate({
    flowId: alert.flowId,
    fix: 'apply_tool_deduplication',
    autoDeploy: true
  });
});
